55	const PROCESSING_FEE = 5;
56	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
57	
58	const EPSILON = 1e-9;
59	
60	const roundUp = (n: number): number => Math.ceil(n - EPSILON);
61	
62	const ITEM_BASE_PREMIUMS: Record<string, number> = {
63	  sword: 100,
64	  amulet: 60,
65	  staff: 80,
66	  potion: 40,
67	  rune: 25,
68	  moonstone: 25,
69	};
70	
71	const withFirstInsuranceSurcharge = (base: number): number =>
72	  base + base * FIRST_INSURANCE_SURCHARGE_RATE;
73	
74	const itemBase = (type: string): number => ITEM_BASE_PREMIUMS[type] ?? 0;
75	
76	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
77	const BLOCK_SIZE = 3;
78	const BLOCK_BASE = 60;
79	
80	const componentGroupBase = (count: number, unitBase: number): number => {
81	  if (count === BLOCK_SIZE) return BLOCK_BASE;
82	  return count * unitBase;
83	};
84	
85	const quotePremium = (items: Item[]): number => {
86	  let policyTotal = 0;
87	  const componentCounts = new Map<string, number>();
88	
89	  for (const item of items) {
90	    if (COMPONENT_TYPES.has(item.type)) {
91	      componentCounts.set(item.type, (componentCounts.get(item.type) ?? 0) + 1);
92	    } else {
93	      policyTotal += withFirstInsuranceSurcharge(itemBase(item.type));
94	    }
95	  }
96	
97	  for (const [type, count] of componentCounts) {
98	    const groupBase = componentGroupBase(count, itemBase(type));
99	    policyTotal += withFirstInsuranceSurcharge(groupBase);
100	  }
101	
102	  return roundUp(policyTotal) + PROCESSING_FEE;
103	};
104	
105	export const processScenario = (scenario: Scenario): ScenarioResult => {
106	  const results: StepResult[] = scenario.steps.map((step) => {
107	    if (step.op === "quote") {
108	      return { premium: quotePremium(step.items) };
109	    }
110	    return { payout: 0, remainingCap: 0 };
111	  });
112	  return { results };
113	};
